//! KAIJU1 — Leech-24 bulk + top-H side-band weight format (encoder + dequant).
//!
//! Spec: `KAIJU1_FORMAT.md` (same directory). Every design choice there cites
//! the 2026-07-08 measurement that forced it; this module implements v1:
//!
//!   * side-band: top-H channels (per-channel granularity — per-tensor was
//!     measured harmful) at 8-bit with per-channel f16 scale;
//!   * bulk: 24-dim blocks on the Leech lattice via `nearest_leech`, coded as
//!     parity(1) + Golay codeword index(12) + 24 ternary residuals
//!     (trit-packed, `3^5 = 243 ≤ 256` — `Gnosis.TritonQuantizationInversion`'s
//!     packing fact) in 7 bytes/block, plus a 4-bit per-block scale
//!     multiplier on an f16 per-row scale.
//!
//! v1 deviation from spec: no 5-bit "sum-fix" field. Clamping residuals to
//! the ternary box already leaves exact lattice membership; the quantizer's
//! geometry benefit comes from the encoder-side Voronoi partition, and the
//! decoder just reconstructs `m + 2c + 4t`. The 5 bits stay reserved.
//!
//! Graceful-degradation contract: residual clamping is only cheap because
//! the partition removed high-H channels first (measured: 91.7% of
//! practical-IQ excess lived in the top H-decile). The encoder therefore
//! REQUIRES an H vector; there is no un-weighted entry point on purpose.

use crate::leech_quantizer::{golay_codewords, nearest_leech, LEECH_DIM};
use crate::math::f16_to_f32;

pub const KAIJU1_MAGIC: u32 = 0x314A_554B; // "KJU1" little-endian
pub const HEADER_BYTES: usize = 16;
/// 1 byte (parity + codeword low bits) + 1 byte (codeword high + reserved)
/// + 5 trit-packed bytes (24 ternary residuals).
pub const LEECH_CODE_BYTES: usize = 7;
const SQRT8: f64 = 2.828_427_124_746_190;
/// Per-block scale heuristic: step = K × block RMS. The ternary residual
/// box covers |w| ≲ 2.5·K·rms, so K trades lattice noise (∝K²) against
/// clamp rate on the tail; K=1.1 covers ~2.7σ (Gaussian clamp <1%) at
/// ~8% lattice relMSE — the bulk lane is low-H by construction, where this
/// is the cheap kind of error.
const STEP_K: f32 = 1.1;

#[derive(Clone, Debug)]
pub struct KaijuHeader {
    pub rows: usize,
    pub cols: usize,
    pub hi_count: usize,
}

/// Partition columns by H: top-H go to the side-band, sized so the bulk
/// column count is an exact multiple of 24. Returns (hi_ids ascending,
/// bulk_ids ascending).
pub fn partition_channels(h: &[f32], hi_frac: f64) -> (Vec<u32>, Vec<u32>) {
    let cols = h.len();
    let mut order: Vec<usize> = (0..cols).collect();
    order.sort_by(|&a, &b| h[b].partial_cmp(&h[a]).unwrap_or(std::cmp::Ordering::Equal));
    let mut hi_count = ((cols as f64) * hi_frac).ceil() as usize;
    // Grow the side-band until bulk is 24-aligned (extra members are the
    // next-highest-H channels — never dropped, never padded).
    while (cols - hi_count) % LEECH_DIM != 0 {
        hi_count += 1;
    }
    let mut hi: Vec<u32> = order[..hi_count].iter().map(|&c| c as u32).collect();
    hi.sort_unstable();
    let hi_set: std::collections::HashSet<u32> = hi.iter().copied().collect();
    let bulk: Vec<u32> = (0..cols as u32).filter(|c| !hi_set.contains(c)).collect();
    (hi, bulk)
}

#[inline]
fn f32_to_f16_bits(v: f32) -> u16 {
    // Round-to-nearest-even via the standard bit dance (positive scales only
    // in this format; subnormals flush to zero — scales are never that small
    // in practice and a zero scale just zeroes the lane).
    let b = v.to_bits();
    let sign = ((b >> 16) & 0x8000) as u16;
    let exp = ((b >> 23) & 0xFF) as i32;
    let man = b & 0x7F_FFFF;
    if exp == 0xFF {
        return sign | 0x7C00; // inf/nan → inf
    }
    let e = exp - 127 + 15;
    if e >= 0x1F {
        return sign | 0x7C00;
    }
    if e <= 0 {
        return sign; // flush
    }
    let mant16 = (man >> 13) as u16;
    let round = (man >> 12) & 1;
    let mut h = sign | ((e as u16) << 10) | mant16;
    h = h.wrapping_add(round as u16);
    h
}

/// Encode one 24-weight block: pick the nearest Λ24 point at the given step,
/// decompose to (parity, Golay index, ternary residuals), write 7 bytes.
/// Returns the count of residuals that had to be clamped (telemetry).
/// Decompose a Λ24 point (Conway integer coords) into (parity, Golay mask,
/// residuals t) with v = m + 2c + 4t. Exact for any lattice point.
fn decompose(v: &[i64; LEECH_DIM]) -> (i64, u32, [i64; LEECH_DIM]) {
    let m = v[0].rem_euclid(2);
    let mut mask = 0u32;
    let mut t = [0i64; LEECH_DIM];
    if m == 0 {
        for (i, &vi) in v.iter().enumerate() {
            if (vi / 2).rem_euclid(2) == 1 {
                mask |= 1 << i;
            }
        }
        for (i, &vi) in v.iter().enumerate() {
            let ci = ((mask >> i) & 1) as i64;
            t[i] = (vi - 2 * ci) / 4;
        }
    } else {
        for (i, &vi) in v.iter().enumerate() {
            if vi.rem_euclid(4) == 3 {
                mask |= 1 << i;
            }
        }
        for (i, &vi) in v.iter().enumerate() {
            let ci = ((mask >> i) & 1) as i64;
            t[i] = (vi - 1 - 2 * ci) / 4;
        }
    }
    (m, mask, t)
}

fn clamp_count(t: &[i64; LEECH_DIM]) -> usize {
    t.iter().filter(|&&x| !(-1..=1).contains(&x)).count()
}

fn encode_block(w: &[f32], step: f64, out: &mut [u8]) -> usize {
    debug_assert_eq!(w.len(), LEECH_DIM);
    debug_assert_eq!(out.len(), LEECH_CODE_BYTES);
    let mut y = [0.0f64; LEECH_DIM];
    for i in 0..LEECH_DIM {
        y[i] = w[i] as f64 / step * SQRT8;
    }
    let v = nearest_leech(y);
    // The ternary residual box is coset-asymmetric (odd half reaches -3..+7).
    // Λ24 = −Λ24, so the mirrored decomposition of −v flips the asymmetry;
    // pick whichever clamps less and store the flip bit (byte1 bit7).
    let (m_p, mask_p, t_p) = decompose(&v);
    let mut neg = [0i64; LEECH_DIM];
    for i in 0..LEECH_DIM {
        neg[i] = -v[i];
    }
    let (m_n, mask_n, t_n) = decompose(&neg);
    let (m, mask, t, flip, clamped) = {
        let cp = clamp_count(&t_p);
        let cn = clamp_count(&t_n);
        if cn < cp {
            (m_n, mask_n, t_n, true, cn)
        } else {
            (m_p, mask_p, t_p, false, cp)
        }
    };
    let cw_idx = golay_codewords()
        .binary_search(&mask)
        .expect("decomposed mask must be a Golay codeword") as u16;

    let mut trits = [0u8; LEECH_DIM];
    for i in 0..LEECH_DIM {
        trits[i] = (t[i].clamp(-1, 1) + 1) as u8; // {-1,0,1} → {0,1,2}
    }

    out[0] = (m as u8) | (((cw_idx & 0x7F) as u8) << 1);
    out[1] = ((cw_idx >> 7) as u8) | if flip { 0x80 } else { 0 };
    for (b, chunk) in trits.chunks(5).enumerate() {
        let mut acc = 0u8;
        for &tr in chunk.iter().rev() {
            acc = acc * 3 + tr;
        }
        out[2 + b] = acc;
    }
    clamped
}

/// Decode one 7-byte LeechCode block into 24 weights at the given step.
pub fn decode_block(code: &[u8], step: f64, out: &mut [f32]) {
    debug_assert_eq!(code.len(), LEECH_CODE_BYTES);
    debug_assert_eq!(out.len(), LEECH_DIM);
    let m = (code[0] & 1) as i64;
    let flip = code[1] & 0x80 != 0;
    let cw_idx = ((code[0] >> 1) as usize) | (((code[1] & 0x1F) as usize) << 7);
    let mask = golay_codewords()[cw_idx & 0xFFF];
    let mut trits = [0i64; LEECH_DIM];
    for b in 0..5 {
        let mut acc = code[2 + b];
        for k in 0..5 {
            let idx = b * 5 + k;
            if idx < LEECH_DIM {
                trits[idx] = (acc % 3) as i64 - 1;
                acc /= 3;
            }
        }
    }
    let sign = if flip { -1.0 } else { 1.0 };
    for i in 0..LEECH_DIM {
        let ci = ((mask >> i) & 1) as i64;
        let vi = m + 2 * ci + 4 * trits[i];
        out[i] = (sign * vi as f64 / SQRT8 * step) as f32;
    }
}

/// Byte size of an encoded tensor with the given shape.
pub fn encoded_size(rows: usize, cols: usize, hi_count: usize) -> usize {
    let bulk_cols = cols - hi_count;
    let blocks = bulk_cols / LEECH_DIM;
    let hi_band = hi_count * (2 + rows);
    // per row: f16 row_scale + packed 4-bit block multipliers + codes
    let row_bytes = 2 + blocks.div_ceil(2) + blocks * LEECH_CODE_BYTES;
    HEADER_BYTES + hi_count * 4 + hi_band + rows * row_bytes
}

/// Encode a rows×cols f32 tensor. `h` = per-input-channel importance
/// (imatrix). Returns the encoded bytes plus clamp-rate telemetry.
///
/// `fisher_steps` = the Fisher-weighted bulk step-search radius. `0` reproduces
/// the legacy unweighted-RMS step exactly (byte-identical). `K ≥ 1` makes the
/// BULK lane importance-aware: per block, the 4-bit step multiplier is chosen
/// to minimize the god-formula excess `Σ_{i∈block} Hᵢ (Wᵢ − Ŵᵢ)²` over the
/// candidate window `q₀ ± K`, instead of leaving every bulk block at the
/// unweighted-MSE-optimal step. This is the same use of the imatrix that
/// llama.cpp's i-quants make (weighted scale search); v1 previously used H
/// ONLY to pick the side-band, so the ppl-driving bulk 90% ignored importance.
/// The chosen step is a *stored* quantity (the 4-bit multiplier), so the decoder
/// needs no imatrix — the isotropic Leech reconstruction is unchanged.
pub fn encode_kaiju1(
    w: &[f32],
    rows: usize,
    cols: usize,
    h: &[f32],
    hi_frac: f64,
    fisher_steps: usize,
) -> (Vec<u8>, f64) {
    assert_eq!(w.len(), rows * cols);
    assert_eq!(h.len(), cols);
    let (hi, bulk) = partition_channels(h, hi_frac);
    let hi_count = hi.len();
    let bulk_blocks = bulk.len() / LEECH_DIM;
    let mut out = Vec::with_capacity(encoded_size(rows, cols, hi_count));

    out.extend_from_slice(&KAIJU1_MAGIC.to_le_bytes());
    out.extend_from_slice(&(rows as u32).to_le_bytes());
    out.extend_from_slice(&(cols as u32).to_le_bytes());
    out.extend_from_slice(&(hi_count as u32).to_le_bytes());
    for &c in &hi {
        out.extend_from_slice(&c.to_le_bytes());
    }

    // Side-band: per hi channel, f16 scale + i8 × rows (column-contiguous).
    for &c in &hi {
        let mut amax = 0.0f32;
        for r in 0..rows {
            amax = amax.max(w[r * cols + c as usize].abs());
        }
        let scale = if amax > 0.0 { amax / 127.0 } else { 1.0 };
        out.extend_from_slice(&f32_to_f16_bits(scale).to_le_bytes());
        for r in 0..rows {
            let q = (w[r * cols + c as usize] / scale).round().clamp(-127.0, 127.0) as i8;
            out.push(q as u8);
        }
    }

    // Bulk rows — row-parallel (encode-once cost dominated by nearest_leech).
    use rayon::prelude::*;
    let row_results: Vec<(Vec<u8>, usize, usize)> = (0..rows)
        .into_par_iter()
        .map(|r| encode_bulk_row(w, r, cols, &bulk, bulk_blocks, h, fisher_steps))
        .collect();
    let mut clamped_total = 0usize;
    let mut resid_total = 0usize;
    for (row_bytes, clamped, resid) in row_results {
        out.extend_from_slice(&row_bytes);
        clamped_total += clamped;
        resid_total += resid;
    }
    let clamp_rate = clamped_total as f64 / resid_total.max(1) as f64;
    (out, clamp_rate)
}

/// H-weighted reconstruction error of one 24-block at a given step:
/// `Σ_i Hᵢ (wᵢ − decode(encode(wᵢ)))²`. Returns (weighted_error, code, clamped).
/// This is an exact round-trip (real `encode_block`/`decode_block`), so the
/// step chosen against it is the true god-formula-excess minimizer among the
/// achievable steps — not a proxy.
fn block_weighted_err(
    blk: &[f32],
    hblk: &[f32],
    step: f64,
) -> (f64, [u8; LEECH_CODE_BYTES], usize) {
    let mut code = [0u8; LEECH_CODE_BYTES];
    let clamped = encode_block(blk, step, &mut code);
    let mut rec = [0.0f32; LEECH_DIM];
    decode_block(&code, step, &mut rec);
    let mut err = 0.0f64;
    for i in 0..LEECH_DIM {
        let d = (blk[i] - rec[i]) as f64;
        err += hblk[i] as f64 * d * d;
    }
    (err, code, clamped)
}

/// Encode one bulk row: returns (bytes, clamped_count, residual_count).
fn encode_bulk_row(
    w: &[f32],
    r: usize,
    cols: usize,
    bulk: &[u32],
    bulk_blocks: usize,
    h: &[f32],
    fisher_steps: usize,
) -> (Vec<u8>, usize, usize) {
    let mut out = Vec::with_capacity(2 + bulk_blocks.div_ceil(2) + bulk_blocks * LEECH_CODE_BYTES);
    let mut clamped_total = 0usize;
    let mut resid_total = 0usize;
    {
        // Gather bulk values + per-block H + per-block ideal steps.
        let mut vals = vec![0.0f32; bulk.len()];
        let mut hval = vec![0.0f32; bulk.len()];
        for (k, &c) in bulk.iter().enumerate() {
            vals[k] = w[r * cols + c as usize];
            hval[k] = h[c as usize];
        }
        let mut ideal = vec![0.0f32; bulk_blocks];
        let mut smax = 0.0f32;
        for b in 0..bulk_blocks {
            let blk = &vals[b * LEECH_DIM..(b + 1) * LEECH_DIM];
            let rms = (blk.iter().map(|&v| v * v).sum::<f32>() / LEECH_DIM as f32).sqrt();
            ideal[b] = (rms * STEP_K).max(1e-8);
            smax = smax.max(ideal[b]);
        }
        let row_scale = if smax > 0.0 { smax } else { 1e-8 };
        let rs_bits = f32_to_f16_bits(row_scale);
        out.extend_from_slice(&rs_bits.to_le_bytes());
        let row_scale = f16_to_f32(rs_bits); // encode with the value the decoder sees
        // 4-bit multipliers: step_b = row_scale × (q+1)/16, q ∈ 0..=15.
        // q₀ = the legacy unweighted-RMS choice; the Fisher search (if enabled)
        // moves it to the excess-minimizing multiplier in the ±K window.
        let mut quants = vec![0u8; bulk_blocks];
        for b in 0..bulk_blocks {
            let q0 = (((ideal[b] / row_scale) * 16.0).round() as i32 - 1).clamp(0, 15);
            if fisher_steps == 0 {
                quants[b] = q0 as u8;
                continue;
            }
            let blk = &vals[b * LEECH_DIM..(b + 1) * LEECH_DIM];
            let hblk = &hval[b * LEECH_DIM..(b + 1) * LEECH_DIM];
            let lo = (q0 - fisher_steps as i32).max(0);
            let hi = (q0 + fisher_steps as i32).min(15);
            let mut best_q = q0;
            let mut best_err = f64::INFINITY;
            for q in lo..=hi {
                let step = row_scale * (q as f32 + 1.0) / 16.0;
                let (err, _, _) = block_weighted_err(blk, hblk, step as f64);
                if err < best_err {
                    best_err = err;
                    best_q = q;
                }
            }
            quants[b] = best_q as u8;
        }
        for pair in quants.chunks(2) {
            let lo = pair[0];
            let hi_nib = if pair.len() > 1 { pair[1] } else { 0 };
            out.push(lo | (hi_nib << 4));
        }
        let mut code = [0u8; LEECH_CODE_BYTES];
        for b in 0..bulk_blocks {
            let step = row_scale * (quants[b] as f32 + 1.0) / 16.0;
            let blk = &vals[b * LEECH_DIM..(b + 1) * LEECH_DIM];
            clamped_total += encode_block(blk, step as f64, &mut code);
            resid_total += LEECH_DIM;
            out.extend_from_slice(&code);
        }
    }
    (out, clamped_total, resid_total)
}

/// Parse the header + hi index of an encoded tensor.
pub fn read_header(bytes: &[u8]) -> Result<(KaijuHeader, Vec<u32>), String> {
    if bytes.len() < HEADER_BYTES {
        return Err("kaiju1: short header".into());
    }
    let magic = u32::from_le_bytes(bytes[0..4].try_into().unwrap());
    if magic != KAIJU1_MAGIC {
        return Err(format!("kaiju1: bad magic {magic:#x}"));
    }
    let rows = u32::from_le_bytes(bytes[4..8].try_into().unwrap()) as usize;
    let cols = u32::from_le_bytes(bytes[8..12].try_into().unwrap()) as usize;
    let hi_count = u32::from_le_bytes(bytes[12..16].try_into().unwrap()) as usize;
    let mut hi = Vec::with_capacity(hi_count);
    let mut off = HEADER_BYTES;
    for _ in 0..hi_count {
        hi.push(u32::from_le_bytes(bytes[off..off + 4].try_into().unwrap()));
        off += 4;
    }
    Ok((KaijuHeader { rows, cols, hi_count }, hi))
}

/// Parsed tensor layout — build ONCE per tensor (or per matvec), then
/// dequantize rows without re-parsing the header or rebuilding the channel
/// index maps. The per-row wrapper below re-parses every call and is only
/// appropriate for one-off lookups (embeddings); hot loops must use this.
pub struct Kaiju1Layout {
    pub rows: usize,
    pub cols: usize,
    hi: Vec<u32>,
    hi_scales: Vec<f32>,
    hi_index_end: usize,
    hi_band_bytes: usize,
    bulk_start: usize,
    row_bytes: usize,
    blocks: usize,
    bulk_ids: Vec<u32>,
}

impl Kaiju1Layout {
    pub fn parse(bytes: &[u8]) -> Result<Self, String> {
        let (hdr, hi) = read_header(bytes)?;
        let hi_count = hdr.hi_count;
        let bulk_cols = hdr.cols - hi_count;
        let blocks = bulk_cols / LEECH_DIM;
        let hi_index_end = HEADER_BYTES + hi_count * 4;
        let hi_band_bytes = 2 + hdr.rows;
        let mut hi_scales = Vec::with_capacity(hi_count);
        for j in 0..hi_count {
            let base = hi_index_end + j * hi_band_bytes;
            hi_scales.push(f16_to_f32(u16::from_le_bytes([bytes[base], bytes[base + 1]])));
        }
        let hi_set: std::collections::HashSet<u32> = hi.iter().copied().collect();
        let bulk_ids: Vec<u32> =
            (0..hdr.cols as u32).filter(|c| !hi_set.contains(c)).collect();
        Ok(Self {
            rows: hdr.rows,
            cols: hdr.cols,
            hi,
            hi_scales,
            hi_index_end,
            hi_band_bytes,
            bulk_start: hi_index_end + hi_count * hi_band_bytes,
            row_bytes: 2 + blocks.div_ceil(2) + blocks * LEECH_CODE_BYTES,
            blocks,
            bulk_ids,
        })
    }

    pub fn dequant_row(&self, out: &mut [f32], bytes: &[u8], row_idx: usize) {
        for (j, &c) in self.hi.iter().enumerate() {
            let base = self.hi_index_end + j * self.hi_band_bytes;
            let q = bytes[base + 2 + row_idx] as i8;
            out[c as usize] = self.hi_scales[j] * q as f32;
        }
        let rbase = self.bulk_start + row_idx * self.row_bytes;
        let row_scale = f16_to_f32(u16::from_le_bytes([bytes[rbase], bytes[rbase + 1]]));
        let qbase = rbase + 2;
        let cbase = qbase + self.blocks.div_ceil(2);
        let mut blk = [0.0f32; LEECH_DIM];
        for b in 0..self.blocks {
            let qbyte = bytes[qbase + b / 2];
            let q = if b % 2 == 0 { qbyte & 0xF } else { qbyte >> 4 };
            let step = row_scale * (q as f32 + 1.0) / 16.0;
            let code = &bytes[cbase + b * LEECH_CODE_BYTES..cbase + (b + 1) * LEECH_CODE_BYTES];
            decode_block(code, step as f64, &mut blk);
            for i in 0..LEECH_DIM {
                out[self.bulk_ids[b * LEECH_DIM + i] as usize] = blk[i];
            }
        }
    }
}

/// Dequantize one row (same signature family as `iq_dequant`). Re-parses
/// the layout every call — fine for single-row lookups, NOT for matvec
/// loops (use [`Kaiju1Layout`] there).
pub fn dequantize_kaiju1_row(out: &mut [f32], bytes: &[u8], row_idx: usize, cols: usize) {
    let layout = Kaiju1Layout::parse(bytes).expect("kaiju1 header");
    assert_eq!(layout.cols, cols);
    layout.dequant_row(out, bytes, row_idx);
}

#[cfg(test)]
mod tests {
    use super::*;

    fn xorshift(state: &mut u64) -> f32 {
        *state ^= *state << 13;
        *state ^= *state >> 7;
        *state ^= *state << 17;
        ((*state >> 11) as f64 / (1u64 << 53) as f64) as f32 - 0.5
    }

    fn gaussian_ish(state: &mut u64) -> f32 {
        // Sum of uniforms ≈ Gaussian; fine for codec tests.
        (0..6).map(|_| xorshift(state)).sum::<f32>() / 1.2247
    }

    #[test]
    fn block_roundtrip_reconstructs_lattice_projection() {
        let mut state = 0x1234_5678_9abc_def0u64;
        for _ in 0..200 {
            let w: Vec<f32> = (0..LEECH_DIM).map(|_| gaussian_ish(&mut state) * 0.02).collect();
            let step = 0.02 * 0.9;
            let mut code = [0u8; LEECH_CODE_BYTES];
            encode_block(&w, step as f64, &mut code);
            let mut out = [0.0f32; LEECH_DIM];
            decode_block(&code, step as f64, &mut out);
            // Re-encoding the DECODED values must be a fixed point (decoded
            // points are representable exactly).
            // Idempotency only holds for clamp-free blocks: clamping leaves
            // the lattice (sum congruence broken), so re-encoding such a
            // block legitimately re-snaps it. Clamp-free decodes ARE genuine
            // Λ24 points and must be exact fixed points.
            let mut probe = [0u8; LEECH_CODE_BYTES];
            let first_clamped = encode_block(&w, step as f64, &mut probe);
            if first_clamped > 0 {
                continue;
            }
            let mut code2 = [0u8; LEECH_CODE_BYTES];
            let clamped = encode_block(&out, step as f64, &mut code2);
            let mut out2 = [0.0f32; LEECH_DIM];
            decode_block(&code2, step as f64, &mut out2);
            assert_eq!(clamped, 0, "decoded lattice points must re-encode without clamping");
            for i in 0..LEECH_DIM {
                assert!(
                    (out[i] - out2[i]).abs() < 1e-6,
                    "idempotent decode: {} vs {}",
                    out[i],
                    out2[i]
                );
            }
        }
    }

    #[test]
    fn tensor_roundtrip_shape_and_error_budget() {
        let rows = 6usize;
        let cols = 3 * LEECH_DIM + 8; // forces hi_count adjustment to 24-align
        let mut state = 0xdead_beef_cafe_f00du64;
        let w: Vec<f32> = (0..rows * cols).map(|_| gaussian_ish(&mut state) * 0.01).collect();
        // H: one screaming outlier channel + mild ramp.
        let mut h: Vec<f32> = (0..cols).map(|c| 1.0 + c as f32 * 0.01).collect();
        h[5] = 1e6;
        let (bytes, clamp_rate) = encode_kaiju1(&w, rows, cols, &h, 0.10, 0);
        let (hdr, hi) = read_header(&bytes).unwrap();
        assert_eq!(hdr.rows, rows);
        assert_eq!(hdr.cols, cols);
        assert_eq!((cols - hdr.hi_count) % LEECH_DIM, 0);
        assert!(hi.contains(&5), "the high-H outlier channel must be in the side-band");
        assert_eq!(bytes.len(), encoded_size(rows, cols, hdr.hi_count));
        assert!(clamp_rate < 0.35, "clamp rate too high: {clamp_rate}");

        let mut num = 0.0f64;
        let mut den = 0.0f64;
        let mut out = vec![0.0f32; cols];
        for r in 0..rows {
            dequantize_kaiju1_row(&mut out, &bytes, r, cols);
            for c in 0..cols {
                let e = (w[r * cols + c] - out[c]) as f64;
                num += e * e;
                den += (w[r * cols + c] as f64).powi(2);
            }
        }
        let rel = num / den;
        eprintln!("[diag] clamp_rate={clamp_rate:.4} relMSE={rel:.4}");
        assert!(rel < 0.15, "relative MSE too high for the budget: {rel} (clamp {clamp_rate:.4})");
    }

    #[test]
    fn side_band_channel_is_near_exact() {
        let rows = 4usize;
        let cols = LEECH_DIM + 8;
        let mut w = vec![0.01f32; rows * cols];
        // Outlier channel with huge weights.
        for r in 0..rows {
            w[r * cols + 3] = 5.0 + r as f32;
        }
        let mut h = vec![1.0f32; cols];
        h[3] = 1e9;
        let (bytes, _) = encode_kaiju1(&w, rows, cols, &h, 0.05, 0);
        let mut out = vec![0.0f32; cols];
        for r in 0..rows {
            dequantize_kaiju1_row(&mut out, &bytes, r, cols);
            let truth = 5.0 + r as f32;
            assert!(
                (out[3] - truth).abs() / truth < 0.02,
                "side-band must carry outliers near-exactly: {} vs {truth}",
                out[3]
            );
        }
    }

    /// Total H-weighted excess `Σ_{r,c} H_c (W − Ŵ)²` — the god-formula
    /// quantity the Fisher step search is supposed to minimize.
    fn weighted_excess(w: &[f32], bytes: &[u8], rows: usize, cols: usize, h: &[f32]) -> f64 {
        let mut out = vec![0.0f32; cols];
        let mut acc = 0.0f64;
        for r in 0..rows {
            dequantize_kaiju1_row(&mut out, bytes, r, cols);
            for c in 0..cols {
                let d = (w[r * cols + c] - out[c]) as f64;
                acc += h[c] as f64 * d * d;
            }
        }
        acc
    }

    #[test]
    fn fisher_search_lowers_weighted_excess_at_equal_size() {
        // A bulk-heavy tensor where importance is skewed WITHIN each 24-block:
        // one channel per block carries high H, so the unweighted-RMS step is
        // the wrong step for the ppl-relevant coordinate. The Fisher search
        // must lower the H-weighted excess without spending a single extra byte.
        let rows = 8usize;
        let cols = 4 * LEECH_DIM; // all bulk (hi_frac small, 24-aligned)
        let mut state = 0x00c0_ffee_1234_5678u64;
        let w: Vec<f32> = (0..rows * cols).map(|_| gaussian_ish(&mut state) * 0.03).collect();
        // Skewed H: every 24th channel is ~500× more important than its block.
        let mut h: Vec<f32> = (0..cols).map(|_| 1.0f32).collect();
        for b in 0..(cols / LEECH_DIM) {
            h[b * LEECH_DIM + 7] = 500.0;
        }
        // Tiny side-band so the comparison is dominated by the bulk lane.
        let (legacy, _) = encode_kaiju1(&w, rows, cols, &h, 0.02, 0);
        let (fisher, _) = encode_kaiju1(&w, rows, cols, &h, 0.02, 3);

        assert_eq!(
            legacy.len(),
            fisher.len(),
            "Fisher search must not change the byte size (only the stored step multipliers)"
        );
        let ex_legacy = weighted_excess(&w, &legacy, rows, cols, &h);
        let ex_fisher = weighted_excess(&w, &fisher, rows, cols, &h);
        eprintln!("[diag] weighted excess: legacy={ex_legacy:.4} fisher={ex_fisher:.4} ratio={:.4}",
            ex_fisher / ex_legacy.max(1e-12));
        // Per-block argmin over the SAME candidate window can never be worse
        // than the legacy q₀ (which is always in the window), so the total is
        // monotonically ≤ legacy; on this skewed H it is strictly better.
        assert!(
            ex_fisher <= ex_legacy + 1e-9,
            "Fisher excess {ex_fisher} must not exceed legacy {ex_legacy}"
        );
        assert!(
            ex_fisher < ex_legacy * 0.999,
            "Fisher search should strictly lower the skewed-H excess: {ex_fisher} vs {ex_legacy}"
        );
    }
}
